solution_code:
#include <stdio.h>
#include <signal.h>
int main(void) {
    sigset_t set;
    sigemptyset(&set);
    sigaddset(&set, SIGINT);
    sigaddset(&set, SIGTERM);
    sigaddset(&set, SIGCHLD);
    printf("SIGINT  membre: %d\n", sigismember(&set, SIGINT));
    printf("SIGTERM membre: %d\n", sigismember(&set, SIGTERM));
    printf("SIGCHLD membre: %d\n", sigismember(&set, SIGCHLD));
    printf("SIGKILL membre: %d\n", sigismember(&set, SIGKILL));
    printf("SIGUSR1 membre: %d\n", sigismember(&set, SIGUSR1));
    sigdelset(&set, SIGTERM);
    printf("SIGTERM apres del: %d\n", sigismember(&set, SIGTERM));
    return 0;
}

