#include <stdio.h>
#include <signal.h>

// ★ Stage 0 — Exemple complet
int main(void) {
    sigset_t set;
    sigemptyset(&set);        // ★ TOUJOURS initialiser avant d'utiliser
    sigaddset(&set, SIGINT);  // ★ ajoute SIGINT (2) au masque
    sigaddset(&set, SIGTERM); // ★ ajoute SIGTERM (15)
    sigaddset(&set, SIGCHLD); // ★ ajoute SIGCHLD (17)
    printf("SIGINT  membre: %d\n", sigismember(&set, SIGINT));  // ★ 1 = présent
    printf("SIGTERM membre: %d\n", sigismember(&set, SIGTERM));
    printf("SIGCHLD membre: %d\n", sigismember(&set, SIGCHLD));
    printf("SIGKILL membre: %d\n", sigismember(&set, SIGKILL)); // ★ 0 = absent
    printf("SIGUSR1 membre: %d\n", sigismember(&set, SIGUSR1));
    sigdelset(&set, SIGTERM); // ★ retire SIGTERM du masque
    printf("SIGTERM apres del: %d\n", sigismember(&set, SIGTERM)); // ★ 0
    return 0;
}

